SELECT ?player ?playerLabel ?salary WHERE {
  wd:Q1163715 wdt:P355 ?team.
  ?team wdt:P54 ?player.
  ?player wdt:P3618 ?salary.
  FILTER(DATATYPE(?salary) = xsd:decimal)
  OPTIONAL { ?player rdfs:label ?playerLabel FILTER (lang(?playerLabel) = "en") }
}
ORDER BY DESC(?salary)
LIMIT 1

